const input = items[0].json;
const payload = input.body;

// Extrair dados do comprador
const phone = payload.data.buyer.checkout_phone || '';
const productName = payload.data.product.name || '';

// Verificar se é produto FeetFans
const isFeetFans = productName.toLowerCase().includes('feetfans');

// Formatar telefone para WhatsApp
const formattedPhone = phone.replace(/\D/g, '') + '@c.us';

return [{
  json: {
    name: payload.data.buyer.name || 'Customer',
    email: payload.data.buyer.email || '',
    phone: formattedPhone,
    product: productName,
    isFeetFans: isFeetFans,
    price: payload.data.purchase.price.value || 0
  }
}];
